import { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import Header from '../components/Header';
import { useCart } from '../context/CartContext';
import { Category, MenuItem, Settings } from '../types';

function formatPrice(price: number) {
  return `$${(price / 100).toFixed(2)}`;
}

export default function MenuPage() {
  const { addItem } = useCart();
  const [categories, setCategories] = useState<Category[]>([]);
  const [items, setItems] = useState<MenuItem[]>([]);
  const [settings, setSettings] = useState<Settings | null>(null);
  const [activeCategory, setActiveCategory] = useState<number | null>(null);
  const [error, setError] = useState('');

  useEffect(() => {
    Promise.all([
      fetch('/api/categories').then((res) => res.json()),
      fetch('/api/menu-items').then((res) => res.json()),
      fetch('/api/settings').then((res) => res.json()),
    ])
      .then(([categoryData, itemData, settingsData]) => {
        setCategories(categoryData);
        setItems(itemData);
        setSettings(settingsData);
        if (categoryData.length > 0) {
          setActiveCategory(categoryData[0].id);
        }
      })
      .catch(() => setError('Unable to load menu right now.'));
  }, []);

  const filteredItems = useMemo(() => {
    return items.filter((item) => item.available && (activeCategory === null || item.category_id === activeCategory));
  }, [items, activeCategory]);

  return (
    <div>
      <Header title={settings?.cart_name || 'Food Cart'} subtitle={settings?.tagline || 'Fresh food made fast'} />
      <main style={{ maxWidth: '960px', margin: '0 auto', padding: '16px' }}>
        {settings && !settings.is_open ? (
          <div style={{ background: '#fee2e2', color: '#991b1b', padding: '12px', borderRadius: '8px', marginBottom: '16px' }}>
            We are currently closed. Please check back later.
          </div>
        ) : null}
        {error ? <div style={{ color: '#b91c1c', marginBottom: '16px' }}>{error}</div> : null}
        <div style={{ display: 'flex', gap: '8px', overflowX: 'auto', marginBottom: '16px' }}>
          {categories.map((category) => (
            <button
              key={category.id}
              onClick={() => setActiveCategory(category.id)}
              style={{
                border: 'none',
                borderRadius: '999px',
                padding: '10px 14px',
                background: activeCategory === category.id ? '#f97316' : '#fed7aa',
                color: activeCategory === category.id ? 'white' : '#9a3412',
                cursor: 'pointer',
              }}
            >
              {category.name}
            </button>
          ))}
        </div>
        {filteredItems.length === 0 ? <div>No menu items available.</div> : null}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: '16px' }}>
          {filteredItems.map((item) => (
            <div key={item.id} style={{ background: 'white', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 2px 8px rgba(0,0,0,0.08)' }}>
              <Link to={`/items/${item.id}`} style={{ color: 'inherit', textDecoration: 'none' }}>
                <img src={item.photo_url} alt={item.name} style={{ width: '100%', height: '180px', objectFit: 'cover' }} />
                <div style={{ padding: '12px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', gap: '8px' }}>
                    <strong>{item.name}</strong>
                    <span>{formatPrice(item.price)}</span>
                  </div>
                  <p style={{ margin: '8px 0', color: '#57534e' }}>{item.description}</p>
                </div>
              </Link>
              <div style={{ padding: '0 12px 12px' }}>
                <button
                  disabled={settings ? !settings.is_open : false}
                  onClick={() => addItem(item, 1)}
                  style={{ width: '100%', background: '#ea580c', color: 'white', border: 'none', borderRadius: '8px', padding: '10px', cursor: 'pointer' }}
                >
                  Add to Cart
                </button>
              </div>
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}
```

