## Objective
Create the checkout page with customer name entry, order summary, and order submission.

## Files to write

### frontend/src/pages/CheckoutPage.tsx
```tsx
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import { useCart } from '../context/CartContext';
import { CreateOrderInput, Order } from '../types';

export default function CheckoutPage() {
  const navigate = useNavigate();
  const { items, subtotal, clearCart } = useCart();
  const [customerName, setCustomerName] = useState('');
  const [error, setError] = useState('');
  const [submitting, setSubmitting] = useState(false);

  const placeOrder = async () => {
    if (!customerName.trim()) {
      setError('Please enter your name.');
      return;
    }
    if (items.length === 0) {
      setError('Your cart is empty.');
      return;
    }
    setSubmitting(true);
    setError('');
    const payload: CreateOrderInput = {
      customer_name: customerName.trim(),
      items: items.map((entry) => ({ item_id: entry.item.id, quantity: entry.quantity })),
    };
    try {
      const res = await fetch('/api/orders', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      const data: Order | { detail: string } = await res.json();
      if (!res.ok) {
        setError('detail' in data ? data.detail : 'Unable to place order.');
        setSubmitting(false);
        return;
      }
      clearCart();
      navigate(`/confirmation/${data.id}`);
    } catch {
      setError('Unable to place order. Please try again.');
      setSubmitting(false);
    }
  };

  return (
    <div>
      <Header title="Food Cart" subtitle="Checkout" />
      <main style={{ maxWidth: '720px', margin: '0 auto', padding: '16px' }}>
        <h1>Checkout</h1>
        {items.length === 0 ? <div>Your cart is empty.</div> : null}
        <div style={{ background: 'white', borderRadius: '12px', padding: '16px', marginTop: '12px' }}>
          <label style={{ display: 'block', marginBottom: '8px', fontWeight: 700 }}>Name for pickup</label>
          <input
            value={customerName}
            onChange={(e) => setCustomerName(e.target.value)}
            placeholder="Your name"
            style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #d6d3d1', marginBottom: '16px' }}
          />
          <div style={{ marginBottom: '12px', fontWeight: 700 }}>Order Summary</div>
          <div style={{ display: 'grid', gap: '8px', marginBottom: '12px' }}>
            {items.map((entry) => (
              <div key={entry.item.id} style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span>{entry.item.name} x {entry.quantity}</span>
                <span>${((entry.item.price * entry.quantity) / 100).toFixed(2)}</span>
              </div>
            ))}
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '16px' }}>
            <strong>Total</strong>
            <strong>${(subtotal / 100).toFixed(2)}</strong>
          </div>
          {error ? <div style={{ color: '#b91c1c', marginBottom: '12px' }}>{error}</div> : null}
          <button
            disabled={submitting || items.length === 0}
            onClick={placeOrder}
            style={{ width: '100%', background: '#ea580c', color: 'white', border: 'none', borderRadius: '8px', padding: '12px', cursor: 'pointer' }}
          >
            {submitting ? 'Placing Order...' : 'Place Order'}
          </button>
        </div>
      </main>
    </div>
  );
}
```

