import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import Header from '../components/Header';
import { Order } from '../types';

const LABELS: Record<string, string> = {
  received: 'Received',
  in_progress: 'In Progress',
  ready: 'Ready',
  picked_up: 'Picked Up',
};

export default function OrderStatusPage() {
  const { orderId } = useParams();
  const [order, setOrder] = useState<Order | null>(null);
  const [error, setError] = useState('');

  useEffect(() => {
    let active = true;
    const load = () => {
      fetch(`/api/orders/${orderId}`)
        .then((res) => {
          if (!res.ok) {
            throw new Error('not found');
          }
          return res.json();
        })
        .then((data) => {
          if (active) {
            setOrder(data);
            setError('');
          }
        })
        .catch(() => {
          if (active) {
            setError('Order not found.');
          }
        });
    };
    load();
    const interval = window.setInterval(load, 5000);
    return () => {
      active = false;
      window.clearInterval(interval);
    };
  }, [orderId]);

  return (
    <div>
      <Header title="Food Cart" subtitle="Order status" />
      <main style={{ maxWidth: '720px', margin: '0 auto', padding: '16px' }}>
        {error ? <div style={{ color: '#b91c1c' }}>{error}</div> : null}
        {order ? (
          <div style={{ background: 'white', borderRadius: '12px', padding: '20px' }}>
            <div style={{ fontSize: '28px', fontWeight: 700, color: '#ea580c', marginBottom: '8px' }}>{order.order_number}</div>
            <div style={{ marginBottom: '16px' }}>Pickup for {order.customer_name}</div>
            <div style={{ display: 'grid', gap: '12px' }}>
              {['received', 'in_progress', 'ready'].map((status) => {
                const active = order.status === status || (status === 'received' && ['in_progress', 'ready', 'picked_up'].includes(order.status)) || (status === 'in_progress' && ['ready', 'picked_up'].includes(order.status));
                return (
                  <div key={status} style={{ padding: '12px', borderRadius: '8px', background: active ? '#fdba74' : '#f5f5f4', color: '#431407' }}>
                    {LABELS[status]}
                  </div>
                );
              })}
            </div>
          </div>
        ) : null}
      </main>
    </div>
  );
}
