import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import { AdminAuthResponse } from '../types';

export default function AdminLoginPage() {
  const navigate = useNavigate();
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');

  const submit = async () => {
    setError('');
    const res = await fetch('/api/settings/verify-pin', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ pin }),
    });
    const data: AdminAuthResponse = await res.json();
    if (data.success) {
      localStorage.setItem('food-cart-admin', 'true');
      navigate('/admin/orders');
      return;
    }
    setError('Invalid PIN.');
  };

  return (
    <div>
      <Header title="Food Cart" subtitle="Admin access" />
      <main style={{ maxWidth: '420px', margin: '0 auto', padding: '16px' }}>
        <div style={{ background: 'white', borderRadius: '12px', padding: '20px' }}>
          <h1 style={{ marginTop: 0 }}>Enter Admin PIN</h1>
          <input
            type="password"
            value={pin}
            onChange={(e) => setPin(e.target.value)}
            style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #d6d3d1', marginBottom: '12px' }}
          />
          {error ? <div style={{ color: '#b91c1c', marginBottom: '12px' }}>{error}</div> : null}
          <button onClick={submit} style={{ width: '100%', background: '#ea580c', color: 'white', border: 'none', borderRadius: '8px', padding: '12px' }}>
            Continue
          </button>
        </div>
      </main>
    </div>
  );
}
```

