import { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import { Order } from '../types';

export default function AdminOrdersPage() {
  const navigate = useNavigate();
  const [orders, setOrders] = useState<Order[]>([]);

  useEffect(() => {
    if (localStorage.getItem('food-cart-admin') !== 'true') {
      navigate('/admin');
      return;
    }
    const load = () => fetch('/api/orders').then((res) => res.json()).then(setOrders);
    load();
    const interval = window.setInterval(load, 5000);
    return () => window.clearInterval(interval);
  }, [navigate]);

  const updateStatus = async (orderId: number, status: string) => {
    const res = await fetch(`/api/orders/${orderId}/status`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status }),
    });
    const updated = await res.json();
    setOrders((current) => current.map((order) => (order.id === orderId ? updated : order)));
  };

  return (
    <div>
      <Header title="Food Cart Admin" subtitle="Orders dashboard" />
      <main style={{ maxWidth: '960px', margin: '0 auto', padding: '16px' }}>
        <div style={{ display: 'flex', gap: '12px', marginBottom: '16px' }}>
          <Link to="/admin/orders" style={{ color: '#c2410c' }}>Orders</Link>
          <Link to="/admin/menu" style={{ color: '#c2410c' }}>Menu</Link>
          <Link to="/admin/settings" style={{ color: '#c2410c' }}>Settings</Link>
        </div>
        <div style={{ display: 'grid', gap: '12px' }}>
          {orders.map((order) => (
            <div key={order.id} style={{ background: 'white', borderRadius: '12px', padding: '16px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', gap: '12px', marginBottom: '8px' }}>
                <div>
                  <strong>{order.order_number}</strong> — {order.customer_name}
                </div>
                <div style={{ color: '#9a3412', fontWeight: 700 }}>{order.status}</div>
              </div>
              <div style={{ marginBottom: '12px' }}>
                {order.items.map((item) => `${item.item_name} x ${item.quantity}`).join(', ')}
              </div>
              <div style={{ display: 'flex', gap: '8px' }}>
                <button onClick={() => updateStatus(order.id, 'in_progress')} style={{ border: 'none', borderRadius: '8px', padding: '10px 12px', background: '#fed7aa' }}>Mark In Progress</button>
                <button onClick={() => updateStatus(order.id, 'ready')} style={{ border: 'none', borderRadius: '8px', padding: '10px 12px', background: '#fdba74' }}>Mark Ready</button>
                <button onClick={() => updateStatus(order.id, 'picked_up')} style={{ border: 'none', borderRadius: '8px', padding: '10px 12px', background: '#e7e5e4' }}>Picked Up</button>
              </div>
            </div>
          ))}
          {orders.length === 0 ? <div>No orders yet.</div> : null}
        </div>
      </main>
    </div>
  );
}
