import { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import { MenuItem, MenuItemInput } from '../types';

export default function AdminMenuPage() {
  const navigate = useNavigate();
  const [items, setItems] = useState<MenuItem[]>([]);

  useEffect(() => {
    if (localStorage.getItem('food-cart-admin') !== 'true') {
      navigate('/admin');
      return;
    }
    fetch('/api/menu-items').then((res) => res.json()).then(setItems);
  }, [navigate]);

  const toggleAvailability = async (item: MenuItem) => {
    const payload: MenuItemInput = {
      name: item.name,
      description: item.description,
      price: item.price,
      category_id: item.category_id,
      photo_url: item.photo_url,
      available: !item.available,
      sort_order: item.sort_order,
    };
    const res = await fetch(`/api/menu-items/${item.id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    const updated = await res.json();
    setItems((current) => current.map((entry) => (entry.id === item.id ? updated : entry)));
  };

  const deleteItem = async (itemId: number) => {
    await fetch(`/api/menu-items/${itemId}`, { method: 'DELETE' });
    setItems((current) => current.filter((entry) => entry.id !== itemId));
  };

  return (
    <div>
      <Header title="Food Cart Admin" subtitle="Menu manager" />
      <main style={{ maxWidth: '960px', margin: '0 auto', padding: '16px' }}>
        <div style={{ display: 'flex', gap: '12px', marginBottom: '16px' }}>
          <Link to="/admin/orders" style={{ color: '#c2410c' }}>Orders</Link>
          <Link to="/admin/menu" style={{ color: '#c2410c' }}>Menu</Link>
          <Link to="/admin/settings" style={{ color: '#c2410c' }}>Settings</Link>
        </div>
        <div style={{ marginBottom: '16px' }}>
          <Link to="/admin/menu/new" style={{ textDecoration: 'none', background: '#ea580c', color: 'white', borderRadius: '8px', padding: '10px 14px', display: 'inline-block' }}>
            Add New Item
          </Link>
        </div>
        <div style={{ display: 'grid', gap: '12px' }}>
          {items.map((item) => (
            <div key={item.id} style={{ background: 'white', borderRadius: '12px', padding: '16px', display: 'flex', justifyContent: 'space-between', gap: '12px' }}>
              <div>
                <div style={{ fontWeight: 700 }}>{item.name}</div>
                <div>{item.category_name}</div>
                <div>${(item.price / 100).toFixed(2)}</div>
                <div style={{ color: item.available ? '#15803d' : '#b91c1c' }}>{item.available ? 'Available' : 'Unavailable'}</div>
              </div>
              <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                <Link to={`/admin/menu/${item.id}`} style={{ textDecoration: 'none', background: '#fed7aa', color: '#9a3412', borderRadius: '8px', padding: '10px 12px' }}>Edit</Link>
                <button onClick={() => toggleAvailability(item)} style={{ border: 'none', borderRadius: '8px', padding: '10px 12px', background: '#fdba74' }}>Toggle</button>
                <button onClick={() => deleteItem(item.id)} style={{ border: 'none', borderRadius: '8px', padding: '10px 12px', background: '#fee2e2', color: '#991b1b' }}>Delete</button>
              </div>
            </div>
          ))}
          {items.length === 0 ? <div>No menu items found.</div> : null}
        </div>
