import { useEffect, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import Header from '../components/Header';
import { Category, MenuItem, MenuItemInput } from '../types';

const emptyForm: MenuItemInput = {
  name: '',
  description: '',
  price: 0,
  category_id: 0,
  photo_url: '',
  available: true,
  sort_order: 0,
};

export default function AdminItemFormPage() {
  const navigate = useNavigate();
  const { itemId } = useParams();
  const isEdit = itemId !== 'new';
  const [categories, setCategories] = useState<Category[]>([]);
  const [form, setForm] = useState<MenuItemInput>(emptyForm);

  useEffect(() => {
    if (localStorage.getItem('food-cart-admin') !== 'true') {
      navigate('/admin');
      return;
    }
    fetch('/api/categories').then((res) => res.json()).then((data: Category[]) => {
      setCategories(data);
      if (data.length > 0) {
        setForm((current) => ({ ...current, category_id: current.category_id || data[0].id }));
      }
    });
    if (isEdit) {
      fetch(`/api/menu-items/${itemId}`).then((res) => res.json()).then((item: MenuItem) => {
        setForm({
          name: item.name,
          description: item.description,
          price: item.price,
          category_id: item.category_id,
          photo_url: item.photo_url,
          available: item.available,
          sort_order: item.sort_order,
        });
      });
    }
  }, [navigate, isEdit, itemId]);

  const uploadPhoto = async (file: File) => {
    const data = new FormData();
    data.append('file', file);
    const res = await fetch('/api/uploads', { method: 'POST', body: data });
    const result = await res.json();
    setForm((current) => ({ ...current, photo_url: result.url }));
  };

  const save = async () => {
    const url = isEdit ? `/api/menu-items/${itemId}` : '/api/menu-items';
    const method = isEdit ? 'PUT' : 'POST';
    await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(form),
    });
    navigate('/admin/menu');
  };

  return (
    <div>
      <Header title="Food Cart Admin" subtitle={isEdit ? 'Edit item' : 'Add item'} />
      <main style={{ maxWidth: '720px', margin: '0 auto', padding: '16px' }}>
        <Link to="/admin/menu" style={{ color: '#c2410c' }}>← Back to menu</Link>
        <div style={{ background: 'white', borderRadius: '12px', padding: '16px', marginTop: '16px', display: 'grid', gap: '12px' }}>
          <input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="Name" style={{ padding: '12px', borderRadius: '8px', border: '1px solid #d6d3d1' }} />
          <textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} placeholder="Description" style={{ padding: '12px', borderRadius: '8px', border: '1px solid #d6d3d1', minHeight: '100px' }} />
          <input type="number" value={form.price} onChange={(e) => setForm({ ...form, price: Number(e.target.value) })} placeholder="Price in cents" style={{ padding: '12px', borderRadius: '8px', border: '1px solid #d6d3d1' }} />
          <select value={form.category_id} onChange={(e) => setForm({ ...form, category_id: Number(e.target.value) })} style={{ padding: '12px', borderRadius: '8px', border: '1px solid #d6d3d1' }}>
            {categories.map((category) => <option key={category.id} value={category.id}>{category.name}</option>)}
          </select>
          <input value={form.photo_url} onChange={(e) => setForm({ ...form, photo_url: e.target.value })} placeholder="Photo URL" style={{ padding: '12px', borderRadius: '8px', border: '1px solid #d6d3d1' }} />
          <input type="file" accept="image/*" onChange={(e) => e.target.files && uploadPhoto(e.target.files[0])} />
          <input type="number" value={form.sort_order} onChange={(e) => setForm({ ...form, sort_order: Number(e.target.value) })} placeholder="Sort order" style={{ padding: '12px', borderRadius: '8px', border: '1px solid #d6d3d1' }} />
          <label style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
            <input type="checkbox" checked={form.available} onChange={(e) => setForm({ ...form, available: e.target.checked })} />
            Available
          </label>
          <button onClick={save} style={{ background: '#ea580c', color: 'white', border: 'none', borderRadius: '8px', padding: '12px' }}>Save Item</button>
        </div>
      </main>
    </div>
  );
}
